import { latLng, LatLng } from 'leaflet';
import React, { useMemo } from 'react';
import { Polyline, Tooltip } from 'react-leaflet';

import Data from '../json/data.json';

import { RouteData } from './App';
// -------------------------------------------------------------------------
// 表示に使用する値系。
// -------------------------------------------------------------------------

// レベルを元にした、地図で表示する線の色。
const colorFromLevel = [
  'hsl(220,30%,20%)', // 0: 黒
  'hsl(240,70%,50%)', // 1: 青
  'hsl(140,50%,50%)', // 2: 緑
  'hsl(30,80%,60%)', // 3: 橙
  'hsl(0,80%,60%)', // 4: 赤
  'hsl(290,70%,50%)', // 5: 紫
];

// -------------------------------------------------------------------------

/**
 * データの座標のリストを、表示用の座標のリストへ変換する。
 * @param coordinates
 * @returns
 */
const latLngsFromCoordinates = (coordinates: number[][]) => {
  let array: Array<LatLng> = [];

  for (const c of coordinates) {
    array.push(latLng(c[0], c[1]));
  }

  return array;
};

// -------------------------------------------------------------------------

/**
 * データを元に、地図に表示する情報（線）を生成する。
 * @param data
 * @returns
 */
const ItemFromRouteData = (
  data: RouteData,
  setData: React.Dispatch<React.SetStateAction<RouteData | null>>,
) => {
  const ll = latLngsFromCoordinates(data.coordinates);

  const lineColor = colorFromLevel[data.gravelLevel];
  const lineOptions = { color: lineColor, weight: 6 };

  const gra = ` ${'★'.repeat(data.gravelLevel)}`;

  const tooltip = `${data.name}${gra}`;

  const key = `${data.name}-$[data.lat]`;

  // 線がクリックされたときに呼び出されるコールバック。
  // 当該の詳細情報を表示する。
  const eventHandlers = {
    click: () => {
      setData(data);
    },
  };
  // ここは元々 useMemo していたけど、恐らく不要なので削除。
  // const eventHandlers = useMemo(
  //   () => ({
  //     click() {
  //       setData(data);
  //     },
  //   }),
  //   [data, setData],
  // );

  return (
    <Polyline
      positions={ll}
      pathOptions={lineOptions}
      eventHandlers={eventHandlers}
      key={key}
    >
      <Tooltip direction="top">{tooltip}</Tooltip>
    </Polyline>
  );
};

// -------------------------------------------------------------------------

/**
 * 地図に表示する情報のコンポーネント。
 * @returns
 */
export const Items = (props: {
  setData: React.Dispatch<React.SetStateAction<RouteData | null>>;
}) => {
  // メモ化しているけど、最初の1回しか呼び出されていないので不要かも。
  const routes = useMemo(() => Data.routes, []);
  // console.log('Items updated');

  const routeItems = [];
  for (const r of routes) {
    routeItems.push(ItemFromRouteData({ ...r }, props.setData));
  }

  return (
    <>
      {routeItems}
      {/* <Polyline positions={line1} pathOptions={lineOptions}>
        <Tooltip direction="top">
          ツール<b>チップ</b>
        </Tooltip>
      </Polyline> */}
    </>
  );
};
